  interface Router {
    (req: IncomingMessage, res: ServerResponse, next: NextFunction): void;
    handle(req: IncomingMessage, res: ServerResponse, callback: NextFunction): void;
    use(...handlers: RequestHandler[]): Router;
    use(path: string | RegExp | Array<string | RegExp>, ...handlers: RequestHandler[]): Router;
    route(path: string): Route;
    param(name: string, fn: RequestHandler): void;
    stack: unknown[];
    Route: new (path: string) => Route;
  }
  interface RouterConstructor {
    new (options?: RouterOptions): Router;
    (options?: RouterOptions): Router;
    Route: new (path: string) => Route;
  }
  const Router: RouterConstructor;
  export = Router;
}
